class StockPrice {
public:
    StockPrice() {
        maxPrice = INT_MIN;
        minPrice = INT_MAX;
    }

    void update(int timestamp, int price) {
        if (prices.find(timestamp) != prices.end()) {
            prices[timestamp] = price;
            maxPrice = std::max(maxPrice, price);
            minPrice = std::min(minPrice, price);
        } else {
            prices[timestamp] = price;
            maxPrice = std::max(maxPrice, price);
            minPrice = std::min(minPrice, price);
        }
    }

    int current() {
        int maxTimestamp = 0;
        for (auto& pair : prices) {
            if (pair.first > maxTimestamp) {
                maxTimestamp = pair.first;
            }
        }
        return prices[maxTimestamp];
    }

    int maximum() {
        return maxPrice;
    }

    int minimum() {
        return minPrice;
    }
private:
    int maxPrice;
    int minPrice;
    std::unordered_map<int, int> prices;
};
